// QueryChallenge queries the challenge edge of a Suite.
func (c *SuiteClient) QueryChallenge(_m *Suite) *ChallengeQuery {
	query := (&ChallengeClient{config: c.config}).Query()
	query.path = func(context.Context) (fromV *sql.Selector, _ error) {
		id := _m.ID
		step := sqlgraph.NewStep(
			sqlgraph.From(suite.Table, suite.FieldID, id),
			sqlgraph.To(challenge.Table, challenge.FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, suite.ChallengeTable, suite.ChallengeColumn),
		)
		fromV = sqlgraph.Neighbors(_m.driver.Dialect(), step)
		return fromV, nil
	}
	return query
}

